import { useEffect, useState } from "react";

import HodLayout from "../../layouts/HodLayout";

import {
  getMyHodSubmissions
} from "../../api/hodApi";

import {
  useNavigate
} from "react-router-dom";

function HodSubmissions() {

  const navigate =
    useNavigate();

  const [submissions,
    setSubmissions] =
    useState([]);

  useEffect(() => {

    loadSubmissions();

  }, []);

  const loadSubmissions =
    async () => {

      try {

        const response =
          await getMyHodSubmissions();

        setSubmissions(
          response.data.submissions || []
        );

      } catch (error) {

        console.log(error);

      }

    };

  return (

    <HodLayout>

      <div
        style={{
          background:"#fff",
          padding:"25px",
          borderRadius:"12px"
        }}
      >

        <h2>
          My HOD Submissions
        </h2>

        <table
          style={{
            width:"100%",
            borderCollapse:"collapse"
          }}
        >

          <thead>

            <tr>

              <th>Quarter</th>

              <th>Status</th>

              <th>Answered</th>

              <th>Action</th>

            </tr>

          </thead>

          <tbody>

            {
              submissions.map(
                (item) => (

                  <tr
                    key={item._id}
                  >

                    <td>
                      {item.quarter}
                    </td>

                    <td>
                      {item.status}
                    </td>

                    <td>
                      {
                        item.answeredCount
                      }
                      /
                      {
                        item.totalQuestions
                      }
                    </td>

                    <td>

                      <button
                        onClick={() =>
                          navigate(
                            `/hod/questionnaire/${item._id}`
                          )
                        }
                      >
                        Edit
                      </button>

                    </td>

                  </tr>

                )
              )
            }

          </tbody>

        </table>

      </div>

    </HodLayout>

  );

}

export default HodSubmissions;
